-- 1. Canterbury × Web Design
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'web-design',
  'canterbury',
  'Canterbury presents a web design challenge unlike any other town in Kent: your website must simultaneously serve international tourists researching a visit to the Cathedral, students at two major universities comparing local options, and the resident population who form your year-round customer base. Over seven million visitors arrive annually expecting seamless digital experiences, yet the majority of Canterbury businesses still run websites built for a single audience. A restaurant on The King''s Mile needs to appear in a German tourist''s Google search just as effectively as it ranks for a Christ Church student looking for a weeknight deal. We design Canterbury websites that handle this multi-audience complexity, building fast, accessible, mobile-first sites that convert tourists, students, and locals through distinct but cohesive user journeys.',
  'Canterbury''s commercial geography centres on the High Street and St Peter''s Street, flowing through the historic core past Whitefriars Shopping Centre and out toward the Westgate Towers. The King''s Mile draws heavy tourist footfall between the Cathedral and the city walls. University of Kent sits on the hillside above the city, while Canterbury Christ Church University is embedded in the centre, together bringing approximately 30,000 students who shape demand for food, entertainment, and services. Canterbury East and Canterbury West stations connect the city to London Victoria and London St Pancras respectively, making it accessible for day trippers and commuters along the A2/M2 corridor.',
  'Canterbury''s web design market is split between London agencies chasing heritage-sector contracts and budget freelancers serving student-oriented businesses. Many established shops along the High Street and around The Goods Shed still operate on sites built before mobile traffic overtook desktop. Tourism-dependent businesses often rely on third-party platforms like TripAdvisor or Booking.com rather than investing in their own digital presence, surrendering control of their brand and paying commission on every booking.',
  'We approach Canterbury web projects by mapping the three distinct audiences that every city-centre business must serve. For tourism businesses near the Cathedral, we implement multilingual elements and structured data that feeds into Google''s travel results. For student-facing businesses, we prioritise mobile speed and social integration. For year-round local services, we build conversion funnels that generate consistent enquiries regardless of the tourist season cycle.',
  '{"population": 55000, "student_population": 30000, "annual_visitors": "7+ million", "key_areas": ["High Street", "St Peters Street", "The Kings Mile", "Whitefriars", "Wincheap", "Sturry Road"]}',
  '[{"title": "One website trying to serve Canterbury''s three distinct audiences", "description": "A Canterbury business near Whitefriars Shopping Centre needs to speak to international tourists arriving from the Cathedral, students from the University of Kent scrolling on their phones, and local residents from Harbledown and Bridge who want a trusted provider. Most websites are designed for a single audience and fail the other two entirely."}, {"title": "Losing direct bookings to third-party platforms", "description": "Tourism businesses along The King''s Mile surrender up to twenty percent commission on every booking routed through TripAdvisor, Booking.com, or Viator. Without a website that ranks independently and converts visitors directly, Canterbury hospitality businesses are permanently trapped paying platform fees."}, {"title": "Outdated sites that damage credibility in a heritage city", "description": "Canterbury is a UNESCO World Heritage destination where visitors expect quality at every touchpoint. A slow, poorly designed website viewed by a tourist standing outside the Westgate Towers creates an immediate credibility gap that no amount of in-person service can overcome."}]',
  '[{"title": "Multi-audience Canterbury website architecture", "description": "We design distinct user journeys within a single site: tourist-facing content with multilingual hints and booking integration, student-oriented sections optimised for mobile and social sharing, and local-service pages built to generate year-round enquiries from residents across Canterbury and villages like Chartham and Littlebourne."}, {"title": "Direct booking systems that bypass platform commissions", "description": "For Canterbury hospitality and tourism businesses, we build integrated booking functionality that lets customers reserve directly through your site. Combined with strong local SEO, this reduces dependency on commission-heavy platforms and puts you in control of your own customer relationships."}, {"title": "Heritage-grade design quality on modern technology", "description": "Your Canterbury website should reflect the calibre of the city itself. We create bespoke designs that feel premium and trustworthy, built on modern frameworks that deliver sub-two-second load times and perfect mobile rendering for tourists navigating on foot around the Cathedral Quarter."}]',
  '[{"question": "Can you build a Canterbury website that works for tourists and locals?", "answer": "Yes, this is our core approach for Canterbury businesses. We architect sites with distinct user pathways so that a tourist researching from overseas, a University of Kent student on campus, and a local resident in Bridge all find relevant content quickly. Each audience gets tailored calls to action without cluttering the experience for the others."}, {"question": "How long does a Canterbury website project take from start to launch?", "answer": "Most Canterbury projects launch within four to six weeks. Tourism businesses near the Cathedral or The King''s Mile with booking integration requirements may need six to eight weeks. We schedule around seasonal peaks so your site goes live before the busiest visitor periods."}, {"question": "Will my new site rank for Canterbury searches immediately?", "answer": "We build every Canterbury site with on-page SEO foundations from day one, including location-specific schema markup, optimised title tags, and content targeting Canterbury and surrounding villages. Initial ranking improvements typically appear within four to eight weeks for local service terms."}, {"question": "Do you work with businesses outside Canterbury city centre?", "answer": "Absolutely. We serve businesses across the wider Canterbury district including Sturry Road, Wincheap retail park, and surrounding villages like Bridge, Chartham, Littlebourne, and Harbledown. We ensure your site targets the specific areas and postcodes relevant to your customer base."}]',
  'lead-gen'
)
ON CONFLICT (service_slug, town_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
