-- 6. Canterbury × Social Media Setup
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'social-media-setup',
  'canterbury',
  'Social media in Canterbury operates differently from almost any other town in Kent because your potential audience extends far beyond the local population. Seven million annual visitors share photos of the Cathedral on Instagram, tag restaurants on The King''s Mile in their stories, and review experiences on Facebook before they have even left the city walls. Thirty thousand students create a digitally hyper-active audience who discover businesses primarily through social platforms rather than search engines. Meanwhile, local residents in Harbledown, Bridge, and across the Canterbury district use community Facebook groups and Nextdoor as their primary recommendation source. Setting up social media profiles that can harness all three of these dynamics, rather than fumbling through inconsistent posting on a personal account, is foundational for any Canterbury business that wants to grow.',
  'Canterbury''s social media landscape is uniquely visual. The Cathedral, Westgate Towers, Dane John Gardens, and the River Stour provide a photogenic backdrop that makes location-tagged content from Canterbury inherently shareable. The Marlowe Theatre and The Goods Shed near Canterbury West station generate consistent social media buzz through events and markets. University of Kent and Canterbury Christ Church University students create a social-media-native audience that expects businesses to have polished, active profiles. The Canterbury Business Improvement District promotes city-centre events that generate social media activity peaks throughout the year.',
  'Canterbury''s social media presence is split between a few well-run hospitality accounts that leverage the city''s visual appeal effectively and a majority of businesses with incomplete, inconsistent, or abandoned profiles. Tourism businesses tend to have the strongest presence due to natural photo opportunities, but even many Cathedral Quarter restaurants rely on customer-generated content rather than a deliberate strategy. Student-facing businesses often understand social media culturally but lack the professional setup to convert followers into customers.',
  'We set up Canterbury social media profiles to capture all three audience layers from day one. For tourism-oriented businesses, we configure Instagram and Facebook for maximum visual impact with location tagging that taps into Canterbury''s seven million annual visitor searches. For student-facing businesses, we prioritise platforms where University of Kent and Christ Church students are most active. For local services, we establish presence in Canterbury community groups and configure profiles for local search visibility.',
  '{"population": 55000, "student_population": 30000, "annual_visitors": "7+ million", "key_areas": ["Cathedral Quarter", "High Street", "The Marlowe Theatre area", "University of Kent campus", "Christ Church area"]}',
  '[{"title": "Canterbury businesses missing the tourist social media wave", "description": "Millions of visitors photograph Canterbury Cathedral, tag meals on The King''s Mile, and share experiences on Instagram and Facebook. Businesses without properly configured, visually compelling social media profiles are invisible during these moments of peak exposure, when tourists are actively recommending and discovering Canterbury businesses through social platforms."}, {"title": "Inconsistent profiles failing to reach Canterbury''s student market", "description": "Thirty thousand students at the University of Kent and Canterbury Christ Church University discover new businesses almost exclusively through social media. A Canterbury business with a half-finished Facebook page and no Instagram presence simply does not exist to this audience, who will scroll past anything that looks unprofessional or inactive."}, {"title": "Personal accounts mixed with Canterbury business presence", "description": "Too many Canterbury business owners run their company social media from personal accounts, mixing holiday photos with promotional posts. This undermines professionalism, limits access to business analytics and advertising tools, and makes it impossible to build a brand presence that stands on its own in Canterbury''s competitive market."}]',
  '[{"title": "Tourism-optimised Canterbury social media profiles", "description": "We configure your Instagram and Facebook profiles to capture Canterbury''s enormous tourist audience. This includes location-tagged content strategies, hashtag research specific to Canterbury tourism searches, integration with Google Business Profile, and visual branding that reflects the heritage quality visitors expect in a UNESCO city."}, {"title": "Student-ready social media presence for Canterbury businesses", "description": "We set up profiles on the platforms Canterbury''s 30,000 students actually use, with content formats, posting schedules, and engagement strategies tuned to university term calendars. Your profiles will be visually polished, mobile-optimised, and configured to appear when students near the University of Kent or Christ Church campus search for local options."}, {"title": "Complete Canterbury business social media foundation", "description": "We separate your business presence from personal accounts, configure professional profiles with consistent Canterbury-relevant branding across all platforms, set up analytics dashboards, establish posting templates, and integrate social profiles with your website and Google Business listing so everything works together as a unified Canterbury business identity."}]',
  '[{"question": "Which social media platforms matter most for Canterbury businesses?", "answer": "It depends on your primary Canterbury audience. Tourism and hospitality businesses see the strongest returns from Instagram and Facebook, where visitors share visual content from the Cathedral Quarter and The King''s Mile. Student-facing businesses need Instagram and TikTok presence. Local service businesses benefit most from Facebook community group visibility and Google Business integration."}, {"question": "How do I reach Canterbury students through social media?", "answer": "Canterbury students respond to authentic, visually polished content on Instagram and TikTok, posted during term time when 30,000 students are active in the city. We set up your profiles with student-relevant content templates, university term-aligned posting schedules, and targeting that reaches users near the University of Kent and Christ Church campuses."}, {"question": "Can social media help my Canterbury business during quiet tourist periods?", "answer": "Absolutely. A well-configured social media presence keeps your Canterbury business visible to local residents year-round through community groups, local hashtags, and consistent posting. During quieter months, social media shifts focus from tourist acquisition to local engagement and loyalty building with residents across the Canterbury district."}, {"question": "Do you manage ongoing social media posting for Canterbury businesses?", "answer": "This service focuses on professional setup and configuration, giving you the foundations to post effectively. We provide Canterbury-specific content templates, posting schedules aligned to tourist and university calendars, and training so you or your team can maintain a consistent, professional presence. Ongoing management packages are available separately."}]',
  'trust'
)
ON CONFLICT (service_slug, town_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  local_context = EXCLUDED.local_context,
  competition_landscape = EXCLUDED.competition_landscape,
