  layout_variant = EXCLUDED.layout_variant;

-- 7. Canterbury × Digital Marketing
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'digital-marketing',
  'canterbury',
  'Digital marketing in Canterbury demands a level of audience segmentation that most agencies are not equipped to deliver. You cannot run a single Google Ads campaign or email sequence and expect it to resonate with an international tourist planning a Cathedral visit, a University of Kent student searching for a Thursday night venue, and a homeowner in Chartham looking for a reliable plumber. Each audience has different search behaviour, different platform preferences, different decision timelines, and different price sensitivity. The Canterbury businesses that grow consistently are those that run distinct, targeted campaigns for each segment rather than broadcasting a generic message into a market of 55,000 residents, 30,000 students, and seven million annual visitors. We build digital marketing systems that speak to each Canterbury audience in their own language, on their own platforms, at the exact moment they are ready to buy.',
  'Canterbury''s digital marketing landscape is shaped by the A2/M2 corridor connecting London to Dover, which positions the city as both a destination and a gateway. Canterbury East and Canterbury West stations bring commuters and visitors, creating digital touchpoints throughout the day. The High Street and St Peter''s Street form the retail core, while Whitefriars Shopping Centre anchors the chain retail presence. The Canterbury Heritage Museum, Dane John Gardens, and the city walls generate cultural search traffic that spills into commercial queries. Surrounding villages including Bridge, Chartham, Littlebourne, and Harbledown represent a residential catchment that searches for Canterbury services digitally before deciding where to spend.',
  'Canterbury''s digital marketing space is contested by London agencies managing campaigns for national chains in Whitefriars, tourism marketing platforms promoting Canterbury as a destination, and university marketing departments with substantial budgets. Local businesses often compete against these well-funded campaigns with limited budgets and generic targeting. The cost per click for Canterbury tourism keywords is significantly higher than typical Kent service terms, making undisciplined ad spend particularly wasteful.',
  'We segment every Canterbury digital marketing campaign by audience from the outset. Tourist-targeted campaigns run on Google Ads and social media with geographic and language targeting that reaches visitors before and during their Canterbury trip. Student campaigns activate during term times on platforms where the university population is most engaged. Local campaigns target postcodes across the Canterbury district with service-specific messaging. This segmentation ensures every pound of ad spend reaches the right Canterbury audience.',
  '{"population": 55000, "student_population": 30000, "annual_visitors": "7+ million", "key_areas": ["City Centre", "Whitefriars", "Canterbury East", "Canterbury West", "Wincheap", "Sturry Road"]}',
  '[{"title": "Canterbury ad spend wasted on the wrong audiences", "description": "A Canterbury restaurant running Google Ads without audience segmentation pays the same cost per click for a tourist who will visit once, a student who could become a weekly regular, and a London commuter passing through Canterbury West station. Without differentiated campaigns, the marketing budget delivers inconsistent returns and makes ROI measurement impossible."}, {"title": "Competing against Canterbury tourism marketing budgets", "description": "Visit Canterbury, English Heritage, and national travel platforms invest heavily in digital marketing that dominates Canterbury search results and social feeds. Local businesses bidding on the same keywords face inflated costs and reduced visibility unless they adopt strategies that target the commercial-intent searches these organisations leave untouched."}, {"title": "No digital marketing strategy for Canterbury''s off-peak periods", "description": "Many Canterbury businesses market heavily during tourist season and university terms, then go quiet during winter. This feast-or-famine approach fails to build the year-round digital presence needed to sustain revenue from the resident population across Canterbury and surrounding villages like Harbledown and Bridge."}]',
  '[{"title": "Audience-segmented Canterbury digital campaigns", "description": "We build separate campaign structures for Canterbury''s three core audiences: tourists, students, and local residents. Each segment receives tailored ad copy, landing pages, and conversion tracking so you know exactly which Canterbury audience generates the best return and can allocate budget accordingly."}, {"title": "Seasonal Canterbury marketing calendar", "description": "We plan campaigns around Canterbury''s unique calendar: Cathedral events, Marlowe Theatre seasons, university term dates, The Goods Shed market schedules, and Canterbury BID promotions. This ensures your marketing activates when each audience is most receptive and scales back during genuine quiet periods to protect budget."}, {"title": "Canterbury postcode-level targeting for local services", "description": "For service businesses covering the Canterbury district, we run hyperlocal campaigns targeting specific postcodes including CT1, CT2, CT3, and CT4. This reaches residents in Bridge, Chartham, Littlebourne, and Harbledown with messages relevant to their area, delivering qualified local leads at a fraction of the cost of broad Canterbury targeting."}]',
  '[{"question": "How much should a Canterbury business spend on digital marketing?", "answer": "It depends on your target audience and competition level. Canterbury tourism keywords carry premium costs per click, while local service terms are more affordable. We typically recommend Canterbury businesses start with a focused budget targeting their highest-value audience segment, then expand once we have proven ROI data for your specific market."}, {"question": "Can digital marketing help me reach Canterbury''s student population?", "answer": "Students are one of the most responsive digital marketing audiences in Canterbury. We run targeted social media and search campaigns timed to University of Kent and Christ Church term dates, using platforms and formats that resonate with the student demographic. These campaigns can be paused during holidays to preserve budget."}, {"question": "How do I compete with Canterbury tourism marketing budgets?", "answer": "You do not compete head-on. We identify the commercial-intent keywords and platforms that tourism organisations do not target, such as specific service searches from visitors already in Canterbury. By focusing your budget on high-conversion, lower-competition terms, you capture genuine customers without competing against institutional marketing spend."}, {"question": "Should I run digital marketing for my Canterbury business year-round?", "answer": "Yes, but with seasonal adjustments. Canterbury''s resident population of 55,000 needs local services regardless of tourist season. We maintain baseline campaigns targeting the Canterbury district year-round while scaling tourist and student campaigns around their respective peak periods."}]',
  'lead-gen'
)
ON CONFLICT (service_slug, town_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  local_context = EXCLUDED.local_context,
  competition_landscape = EXCLUDED.competition_landscape,
  success_approach = EXCLUDED.success_approach,
