-- 8. Canterbury × Workwear & Print
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'workwear-print',
  'canterbury',
  'In a city that welcomes over seven million visitors annually, every Canterbury business is on display to an audience far larger than its local customer base. A tradesperson''s van parked outside a house near the Canterbury Heritage Museum is seen by hundreds of tourists walking past. Staff uniforms in a restaurant on St Peter''s Street are photographed in the background of countless holiday snaps shared on social media. Printed menus, business cards, and signage in Canterbury''s historic centre are scrutinised by visitors who are primed to notice quality because they are surrounded by a UNESCO World Heritage environment. This level of passive exposure makes professional workwear and print materials disproportionately valuable for Canterbury businesses compared to those in towns where only locals see your brand. Every piece of printed material and every branded garment is a micro-advertisement in a city where millions of people are already paying attention.',
  'Canterbury''s commercial environment places unique demands on workwear and print. The historic city centre with its narrow streets, the Westgate Towers, and the Cathedral Quarter attracts pedestrian traffic that passes directly by local businesses. The Goods Shed farmers market near Canterbury West station showcases artisan producers whose stall branding and packaging directly influence buying decisions. Wincheap retail park and Sturry Road host trades and service businesses whose vehicle livery covers the Canterbury district daily. The Canterbury Business Improvement District organises events throughout the year where professional presentation differentiates participating businesses.',
  'Canterbury''s print and workwear market is served by a mix of national online suppliers offering rock-bottom prices on generic products and a small number of local print shops. Quality varies dramatically. Many Canterbury businesses order the cheapest embroidered polos from online catalogues, resulting in inconsistent branding, poor garment quality, and prints that fade after weeks. The gap between businesses with cohesive, professional branded materials and those with mismatched, low-quality items is immediately apparent on the High Street.',
  'We approach Canterbury workwear and print with the understanding that your materials will be seen by an international audience, not just local customers. This means specifying garment quality and print durability that withstands daily use while maintaining the visual standards expected in a heritage city. We work with Canterbury businesses to develop cohesive ranges that cover every touchpoint: staff uniforms for the shop floor, outdoor workwear for trades, vehicle graphics, printed materials, and event branding.',
  '{"population": 55000, "student_population": 30000, "annual_visitors": "7+ million", "key_areas": ["High Street", "St Peters Street", "Cathedral Quarter", "Wincheap", "Sturry Road", "The Goods Shed"]}',
  '[{"title": "Canterbury''s tourist audience judging your brand by what they see", "description": "Seven million visitors walk Canterbury''s streets each year. When your staff serve them in faded, mismatched uniforms or your van sits parked near the Westgate Towers with peeling graphics, that impression reaches an audience thousands of times larger than in a typical Kent town. In Canterbury, poor presentation is amplified by sheer visitor volume."}, {"title": "Cheap online workwear letting Canterbury businesses down", "description": "Canterbury businesses ordering the cheapest embroidered polos from national catalogues discover the false economy within months: prints crack, colours fade, sizing is inconsistent, and the overall effect looks worse than having no branding at all. In a city where competitors on The King''s Mile invest in quality presentation, this creates an immediate credibility gap."}, {"title": "Inconsistent Canterbury branding across print and workwear", "description": "A Canterbury business with professional signage on St Peter''s Street but staff in unbranded clothes, generic business cards, and a van with clip-art graphics sends contradictory signals. Tourists and residents alike notice the inconsistency, and it undermines the trust that consistent branding is supposed to build."}]',
  '[{"title": "Heritage-grade Canterbury workwear and print quality", "description": "We specify garments and print processes that match the standards expected in a UNESCO Heritage city. Every polo shirt, jacket, and hi-vis vest uses commercial-grade embroidery or print that retains its quality through daily wear and regular washing. Your team will look professional whether serving tourists on The King''s Mile or working on site in Chartham."}, {"title": "Cohesive Canterbury brand deployment across all materials", "description": "We ensure your brand appears consistently across every physical touchpoint: staff uniforms, vehicle livery, business cards, menus, signage, and event materials for Canterbury BID promotions. Everything uses the same colours, fonts, and logo treatments so your business presents a unified professional image across the Canterbury district."}, {"title": "Practical workwear ranges for Canterbury''s diverse businesses", "description": "From front-of-house uniforms for hospitality on the High Street to durable outdoor workwear for trades covering Bridge, Harbledown, and Littlebourne, we build practical ranges that suit your actual working conditions. We manage sizing across your team, coordinate bulk orders for cost efficiency, and maintain stock availability for replacements and new starters."}]',
  '[{"question": "What workwear quality level is appropriate for a Canterbury business?", "answer": "Given Canterbury''s international visitor traffic and the visual standards set by the heritage environment, we recommend mid-to-premium garment ranges with commercial-grade embroidery. This is not about luxury; it is about choosing workwear that still looks sharp after six months of daily use in a city where your appearance is your most visible marketing asset."}, {"question": "Can you match my existing Canterbury brand colours and logo exactly?", "answer": "Yes. We work from your brand guidelines or existing materials to ensure exact colour matching across all garments and print products. For Canterbury businesses without formal brand guidelines, we can establish specifications that ensure consistency whether you are printing business cards for a Marlowe Theatre event or ordering new uniforms for a High Street shop."}, {"question": "How quickly can Canterbury workwear orders be fulfilled?", "answer": "Standard Canterbury workwear orders with embroidery are typically ready within seven to ten working days. Rush orders for Canterbury BID events or seasonal staff can often be accommodated within five working days. We hold stock information for repeat Canterbury clients so reorders can be processed quickly."}, {"question": "Do you provide vehicle graphics for Canterbury trades businesses?", "answer": "Yes. We design and coordinate professional vehicle livery for vans and cars operating across the Canterbury district. Given that your vehicle is seen throughout the city centre, on Sturry Road, at Wincheap, and in surrounding villages daily, professionally designed vehicle graphics are one of the highest-impact branding investments a Canterbury trades business can make."}]',
  'operational'
)
ON CONFLICT (service_slug, town_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  local_context = EXCLUDED.local_context,
  competition_landscape = EXCLUDED.competition_landscape,
